// Time:  O(n^(1/2) * (logn + n^(1/2)))
// Space: O(logn)

class Solution {
public:
    int primePalindrome(int N) {
        if (8 <= N && N <= 11) {
            // any palindrome with even digits is multiple of 11
            return 11;
        }
        for (int i = to_string(N).length() / 2; i < 100000; ++i) {
            const string s = to_string(i), rev_s(s.rbegin(), s.rend());
            int j = stoi(s + rev_s.substr(1));
            if (j >= N && isPrime(j)) {
                return j;
            }
        }
        return -1;
    }

private:
    bool isPrime(int num) {
        if (num < 2 || num % 2 == 0) {
            return num == 2;
        }
        for (int i = 3; i * i <= num; i += 2) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
};

# Time:  O(n^(1/2) * (logn + n^(1/2)))
# Space: O(logn)


class Solution(object):
    def primePalindrome(self, N):
        """
        :type N: int
        :rtype: int
        """
        def is_prime(n):
            if n < 2 or n % 2 == 0:
                return n == 2
            return all(n % d for d in xrange(3, int(n**.5) + 1, 2))

        if 8 <= N <= 11:
            return 11
        for i in xrange(10**(len(str(N))//2), 10**5):
            j = int(str(i) + str(i)[-2::-1])
            if j >= N and is_prime(j):
                return j
